external_knowledge:
; The term "current epidemiological situation" refers to the most recent data available, which in this context is the latest date for each state in the epidemiological_data table; 
; "Recent alerts" are defined as alerts generated within the last 30 days; 
; "Active interventions" are those where the start date is on or before the current date and the end date is either null or on or after the current date.

sql:
SELECT state_name
FROM states
ORDER BY state_name;

